// Compare the two AoT-Harness runs and report the savings.
// Inputs: item 0 = single-provider run, item 1 = mixed-provider run.
const single = $input.first().json;
const mixed  = $input.last().json;

const costA = single.cost?.total_usd ?? 0;
const costB = mixed.cost?.total_usd  ?? 0;
const savingPct = costA > 0 ? ((costA - costB) / costA) * 100 : 0;
const savedUsd  = costA - costB;

return [{ json: {
  goal: single.goal,
  run_a_single: {
    provider: single.provider_used,
    model:    single.model_used,
    cost_usd: costA,
    qa_score: single.qa_score,
    success:  single.success,
  },
  run_b_mixed: {
    decomposer: `${mixed.decomposer_provider_used}/${mixed.decomposer_model_used}`,
    executor:   `${mixed.provider_used}/${mixed.model_used}`,
    cost_usd:   costB,
    qa_score:   mixed.qa_score,
    success:    mixed.success,
  },
  comparison: {
    saved_usd_per_run:    Number(savedUsd.toFixed(6)),
    saved_pct:            Number(savingPct.toFixed(1)),
    annualized_1k_per_mo: Number((savedUsd * 12000).toFixed(2)),
  },
} }];
